var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으으, 눈 부셔.","JPN":"うう……眩しい……","ENG":"Eergh... It's too bright.","TWN":"唔呃，好刺眼。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여긴……? 승부는 어떻게 됐지?","JPN":"ここは……？　勝負はどうなったの？","ENG":"Where am I...? What happened to the match?","TWN":"這裡是……？結果誰輸誰贏？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"엇!? 노엘, 라이카!","JPN":"あっ！？　ノエル、ライカ！","ENG":"Huh? Noelle, Laika!","TWN":"嗯？！洛艾兒、萊卡！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"둘 다 정신 좀 차려봐요!","JPN":"二人ともしっかりしてください！","ENG":"Wake up, you two!","TWN":"你們醒醒！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 여긴 어디예요, 펠리세트?","JPN":"うぅ、ここはどこなんですか、フェリセット？","ENG":"Ooh... Where are we, Félicette?","TWN":"呃呃，這裡是哪裡，費莉塞特？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"분명 떨어지면서 챔피언을 쏴 갈겼던 것까지는 기억이 나는데…….","JPN":"確か、墜落しながらチャンピオンを撃ちまくってて……","ENG":"I remember falling and shooting the champion...","TWN":"我明明記得我一邊降落一邊掃射冠軍……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 다음에 어떻게 됐더라…….","JPN":"そのあとはどうなったんだっけ……","ENG":"But what happened after that...?","TWN":"然後呢……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"호, 혹시 그럼 여긴 천국인 걸까요?!","JPN":"じゃ、じゃあもしかしてここは天国なんでしょうか！？","ENG":"D-do you think that we might be in heaven?!","TWN":"難，難道這裡是天堂？！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 내가 한 번 다녀와 봐서 아는데 천국은 이렇게 안 생겼어.","JPN":"おい、天国には一度行ったことあるけど、こんな場所じゃなかったぞ。","ENG":"Hey, trust me. This looks nothing like heaven. I know because I've been there once already.","TWN":"喂，我之前去過一趟，天堂可不是這個樣子。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"천국이든 아니든 그런 건 상관없어요.","JPN":"天国だろうが、そうじゃなかろうが構いません。","ENG":"Heaven or not, it doesn't matter to me.","TWN":"是不是天堂都無所謂。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"승부는 어떻게 됐죠? 오지만디아스를 쓰러트렸다면 그걸로 충분해요.","JPN":"勝負はどうなったんですか？　オジマンディアスを倒せたのならそれで十分です。","ENG":"I want to know how the match ended. If I beat Ozymandias, that's enough for me.","TWN":"結果到底誰輸誰贏？我只希望有打敗奧茲曼迪亞斯。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 싸웠다─! 카나리아 스쿼드─!","JPN":"よくやった─！　カナリア・スクワッド─！","ENG":"Good game–! Canary Squad–!","TWN":"幹得好—！金絲雀小隊—！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CLAP_02"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"최고의 명경기였어─! 챔피언─!","JPN":"最高の試合だったぞ─！　チャンピオン─！","ENG":"That was the best match ever–! Champion–!","TWN":"這真是一場有史以來最精彩的比賽—！冠軍—！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"이대로 명예의 전당까지 가는 거야!!","JPN":"このまま名誉の殿堂まで突き進め！！","ENG":"Now it's straight to the hall of fame!!","TWN":"就這麼一路走向榮譽的殿堂吧！！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그럼, 그럼! 이 밋치미치는 처음부터 카나리아를 유력한 우승후보라고 생각하고 있었다구!","JPN":"うむうむ！　このミッチーミッチーは最初からカナリアを優勝有力候補だと思っていたとも！","ENG":"Of course!! Mitchie-Mitchie always thought that Canary Squad was a strong contender from the start!","TWN":"沒錯沒錯！米琪一開始就認為金絲雀是最具有潛力的冠軍候選人！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"자, 그럼 시청자 여러분!","JPN":"さて、それでは視聴者のみなさん！","ENG":"Okay then, everyone!","TWN":"那麼，各位觀眾！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"새로운 챔피언의 우승 소감을 한 번 들어봐야겠지?","JPN":"新しいチャンピオンに優勝した感想を聞きたいよね？","ENG":"Shall we hear what our new champions have to say about their win?","TWN":"讓我們來聽聽新冠軍的奪冠感想吧？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그래서 지금 기분이 어때, 펠리세트?","JPN":"というわけで、今の気分は？　フェリセット。","ENG":"Félicette, how are you feeling right now?","TWN":"現在的心情如何，費莉塞特？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"방금 새로운 챔피언이라고 했어요, 미치?","JPN":"新しいチャンピオン、って言いました、ミッチー？","ENG":"Mitchie, did you just say \\"the new champion\\"?","TWN":"你剛剛說新冠軍嗎，米琪？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"ということは……","ENG":"Then that means...","TWN":"意思就是……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 뭘 그렇게 멍하게 있냐, 꼬마 대장?","JPN":"ったく。何ぼけーっとしているんだよ、チビ隊長？","ENG":"Oh, c'mon, Little Captain. Why are you so bloody slow?","TWN":"真是的，你發什麼愣，小不點隊長？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너희들이 이겼어. 이제부터 우리가 새로운 챔피언이야.","JPN":"お前たちが勝ったんだ。これからは俺たちが新しいチャンピオンだ。","ENG":"You won. We're the new champions now.","TWN":"你們贏了，從現在開始我們就是新任冠軍。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"단순한 호위 임무라고 전달 받았는데, 생각보다 일이 커졌네요.","JPN":"単なる護衛任務だと聞いていたのですが、思ったより大事になってしまいましたね。","ENG":"I was told that this was a simple escort mission, but things have snowballed more than I had expected.","TWN":"本來是說只需要簡單做些保鑣的工作，沒想到事情鬧這麼大。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"아무래도 대금을 다시 정산해야겠어요.","JPN":"代金を再計算しないといけません。","ENG":"I believe I'll have to recalculate my fee for this one.","TWN":"我覺得有必要重新計算一下費用。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리가 챔피언을 꺾었다고?","JPN":"私たちがチャンピオンに勝ったのか？","ENG":"We defeated the champion?","TWN":"我們打敗了冠軍？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 그럼 우리는 추락할 때 어떻게 살아남았는데?","JPN":"待って、じゃあ私たちはどうやって墜落から助かったんだ？","ENG":"Wait a minute. But how did we survive the fall?","TWN":"等等，那我們墜落的時候是怎麼活下來的？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이, 설마 너 다 계획이 있었냐? 사실 착지할 방법도 생각해 둔 거지?","JPN":"おこちゃま、まさかすべて計画していたのか？　着地する方法まで？","ENG":"Kid, was this all part of your plan? In truth, you already thought of how to safely land on the ground, didn't you?","TWN":"小鬼，該不會這都在你的計畫之中？其實你有先想好著陸的方法對吧？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……沒有。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지면에 충돌하기 전에 방패로 어떻게든 해볼까 생각해 봤는데…….","JPN":"地面に衝突する前に盾でなんとかしてみようとは考えていたけど……","ENG":"I did think about using the shield to absorb the shock right before impact...","TWN":"在撞擊到地面之前，我是有想用盾牌做點什麼……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"역시 잘 기억이 안 나요.","JPN":"やっぱりよく思い出せないわ。","ENG":"But I can't remember.","TWN":"但又想不太起來。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"대책 없이 저지른 거였어요!?","JPN":"なんの対策もなしであれをやったんですか！？","ENG":"You did all that without a plan in mind?!","TWN":"你沒有先想好對策就那麼做嗎？！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다, 다행이다……. 휘말렸으면 기껏 펜릴 소대에 들어와 놓고 인생 끝장날 뻔했어요…….","JPN":"よ、よかった……巻き込まれていたらせっかくフェンリル小隊に入ったのに、人生終了するところでした……","ENG":"Ph-phew... My life would've been over as soon as I joined Fenrir Squad if I got dragged into that...","TWN":"幸，幸好還活著……萬一不幸死掉，那我好不容易才進入芬里爾小隊有什麼意義……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"확실히 추락할 때 다들 당황했지만…….","JPN":"確かに落下しはじめたときはみんな焦っていましたが……","ENG":"Everyone was in shock when you were falling, but...","TWN":"墜落的時候，大家確實都很驚慌……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 낚아챘어.","JPN":"私が全員助けたわ。","ENG":"I caught you just before hitting the ground.","TWN":"是我拉回來的。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"조금만 늦었으면 최단기 챔피언 기록을 경신했을걸.","JPN":"あと一歩遅かったら、チャンピオン期間最短記録を更新していたわね。","ENG":"Just a bit late, and you'd be famous for being the shortest reigning champion.","TWN":"再晚一點，應該就可以刷新冠軍最短任期。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"오지만디아스…….","JPN":"オジマンディアス……","ENG":"Ozymandias...","TWN":"奧茲曼迪亞斯……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……받아, 챔피언.","JPN":"……受け取りなさい、チャンピオン。","ENG":"...Here you go, champion.","TWN":"……拿去吧，冠軍。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"전력 분석이 부족했던 내 패배네. 이 트로피는 이제 너희 거야.","JPN":"戦力分析が足りていなかった私の負けね。このトロフィーはもうあなたたちのものよ。","ENG":"It's my loss for not analyzing my opponents properly. This trophy is yours now.","TWN":"我認輸，是我戰力分析不夠，這個獎盃是屬於你們的。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이걸로 용서 받았다고 생각하는 건 아니겠죠?","JPN":"これで許されると思っているわけじゃないですよね？","ENG":"You're not thinking that you're forgiven for this, are you?","TWN":"你不會以為你這麼做我就會原諒你吧？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여태까지 누리던 삶으로는 두 번 다시 돌아가지 못할 텐데요.","JPN":"これまでみたいな栄華は二度と取り戻せませんよ。","ENG":"Now, you won't be able to return to your luxurious lifestyle anymore.","TWN":"你再也回不去之前奢華的生活了。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래, 이 환호성이 끝나면 너희 같은 약골에게 졌다고 사방에서 물어뜯겠지.","JPN":"そうね、この歓声が一旦引いたら、あなたたちのような弱い連中に負けたってあらゆるところから言われるでしょうね。","ENG":"I know. And once this applause ends, they'll start bashing me for losing to a couple of weaklings like you.","TWN":"沒錯，等歡呼聲停止後，會有很多人咬著我不放，因為我輸給你們這些無名小卒。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"패배자로서, 대가는 제대로 치를 거야.","JPN":"敗北者として、その報いは受けるわよ。","ENG":"But I'll pay the price of becoming the loser.","TWN":"身為敗將，我會付出代價的。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"결과까지 부정할 만큼 구차하지 않거든.","JPN":"結果すらも否定するほど性根が腐ってはいないわ。","ENG":"I'm not petty enough to deny my defeat.","TWN":"我沒有糟糕到會否定結果。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"다들 보고 있어? 그 콧대 높은 오지만디아스가 순순히 트로피를 넘겼다고!","JPN":"みんな見てる？　あのプライドの塊のオジマンディアスが大人しくトロフィーを渡しちゃった！","ENG":"Did you guys see that? That haughty Ozymandias just gave them the trophy!","TWN":"大家有看到嗎？那個不可一世的奧茲曼迪亞斯乖乖交出獎盃！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"챔피언의 세대 교체가 이루어지는 역사적인 순간─!","JPN":"チャンピオンの世代交代が行われる歴史的な瞬間─！","ENG":"It's a historical moment of a new champion being born–!","TWN":"這是新舊冠軍交接的歷史性瞬間—！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이 순간을 현장에서 직접 볼 수 있다니……!","JPN":"この瞬間を直接現場で見られるなんて……！","ENG":"I just can't believe that I got to watch it happen live...!","TWN":"我竟然能在現場親眼見證這個場面……！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"미치, 너무 감격스러워서 눈물이 나올 것 같다고…….","JPN":"ミッチー、感動しすぎて涙が出ちゃいそう……","ENG":"Mitchie's... so moved! I'm about to cry...","TWN":"米琪心裡太激動了，我好想哭喔……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_CAMERA"},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐해, 꼬맹이. 얼른 받아.","JPN":"何してんだよ、おこちゃま。早く受け取れ。","ENG":"C'mon, kid. Take it.","TWN":"小鬼，你在做什麼？還不快收下。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 트로피 들고 같이 기념 사진 찍어요!","JPN":"はい！　トロフィーを持って、一緒に記念撮影しましょう！","ENG":"Yeah! Let's hold the trophy together and take a picture!","TWN":"對！一起拿著獎盃拍照留念吧！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……아, 네.","JPN":"……あ、はい。","ENG":"...Oh, okay.","TWN":"……喔，好。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"찍어야죠, 사진.","JPN":"記念写真……撮りましょう。","ENG":"Let's take it. The photo, I mean.","TWN":"當然要拍照囉。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"감사합니다, 전 챔피언.","JPN":"ありがとうございます、元チャンピオン。","ENG":"Thank you, former champion.","TWN":"謝謝你，前任冠軍。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ええ。","ENG":"...Yeah.","TWN":"……好。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 아티팩트가 네 손에 들려 있는 걸 보면, 결국 네 엄마는 도시를 배반한 적 없었단 거네.","JPN":"そのアーティファクトがあなたの手にあるってことは、結局あなたのお母さんは都市を裏切ってなかったってことね。","ENG":"And seeing how you're in possession of that Artifact, I guess your mother never betrayed this city after all.","TWN":"那個人造神器就在你手裡，就證明你母親從來沒有背叛過城市。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"챔버에서 잭슨이라는 녀석을 찾아.","JPN":"チェンバーでジャクソンという人物を見つけ出しなさい。","ENG":"Go find a guy named Jackson at Chamber.","TWN":"你去找一個叫作傑森的傢伙。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잘못 증언한 데 대한 사과 대신이라고 생각해, 루이즈.","JPN":"誤った証言をした謝罪代わりよ、ルイーズ。","ENG":"Think of it as my apology for giving a false testimony, Louisé.","TWN":"就當是為著我錯誤的證詞道歉吧，露易絲。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"왜 그렇게 놀란 표정이야? 저 여자가 고백이라도 했어?","JPN":"そんなに驚いた顔して、どうした？　あの女に告白でもされた？","ENG":"Why do you look so surprised? Did that woman propose to you or something?","TWN":"你幹嘛一臉驚訝？那女人跟你告白喔？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아, 아무것도 아니에요.","JPN":"な、何でもないわ。","ENG":"I-it's nothing.","TWN":"沒，沒有。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"복잡한 건 나중에 생각해도 돼.","JPN":"難しいことはあとで考えよう。","ENG":"We'll think about the complicated stuff later.","TWN":"複雜的事等以後再想吧。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지금은 그냥 순수하게 승리를 즐기자고.","JPN":"今は純粋に勝利を楽しもうぜ。","ENG":"Right now, let's just enjoy our victory.","TWN":"現在只需要單純享受勝利的滋味。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……네, 고마워요. 라이카.","JPN":"……ええ、ありがとう。ライカ。","ENG":"...I will. Thank you, Laika.","TWN":"……嗯，謝謝你，萊卡。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 이 은혜 평생 잊지 마라.","JPN":"ああ、一生この恩を忘れるなよ。","ENG":"Yeah, you'd better not forget this.","TWN":"沒錯，這個恩情你一輩子都不能忘。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"가자. 다들 주인공을 기다리고 있으니까.","JPN":"行こう。みんな主人公を待ってる。","ENG":"Let's go. They're all waiting for the woman of the hour.","TWN":"走吧，大家都等候主角呢。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아하하! 승리의 브이, 브이!","JPN":"あはは！　勝利のピース、ピース！","ENG":"Ah hah hah! V for victory! V!","TWN":"哈哈哈！勝利的V！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"해냈어요, 펠리세트! 정말 우승했다구요!","JPN":"やりましたよ、フェリセット！　本当に優勝しちゃったんですよ！","ENG":"We did it, Félicette! We really won!","TWN":"我們做到了，費莉塞特！我們真的奪冠了！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"모두 힘을 합쳐서 꿈을 이루어서 너무 기뻐요!","JPN":"みんなで力を合わせて夢を叶えられて、本当に嬉しいです！","ENG":"I'm so happy that everyone got together and achieved this dream!","TWN":"大家同心協力實現夢想，我真的好開心！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"리그에서 우승해서 펜릴 소대의 이름을 드높였으니, 펜릴 소대 동상이 세워지겠죠?","JPN":"リーグで優勝したことでフェンリル小隊の名もあげられましたし、フェンリル小隊の銅像も建てられるでしょうね？","ENG":"Since we won, the reputation of Fenrir Squad must have gone up. Do you think they'll put up a Fenrir Squad statue?","TWN":"聯賽中奪冠後，芬里爾小隊知名度也因此大大提升，那應該會建一個芬里爾小隊的銅像吧？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 영광을 소대장님과 선배님들께 바칩니다아!!","JPN":"この栄光を、小隊長と先輩方に捧げますぅ！！","ENG":"I dedicate this honor to our commander and my fellow Fenrir Squad members!!","TWN":"我要把這份榮耀獻給小隊長和前輩們！！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하하, 동상까지는 몰라도 우릴 본딴 액션 피규어는 나올 거예요.","JPN":"あはは、銅像が建つかどうかはわかりませんが、私たちのフィギュアぐらいなら作られると思いますよ。","ENG":"Haha, I don't know about a statue, but they will make action figures of us.","TWN":"哈哈，建不建銅像不確定，但應該會出我們的周邊公仔。"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오! 정말요?! ","JPN":"おお！　本当ですか！？ ","ENG":"Ooh! Really?!","TWN":"哇喔！真的嗎？！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 쪼잔하게 액션 피규어가 다 뭐냐?","JPN":"おい、アクションフィギュアだなんてスケールが小さいだろ。","ENG":"Why are you so excited about some action figures like a cheapskate?","TWN":"喂，你們這些沒見過世面的傢伙，公仔算什麼？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"리그 상금만으로도 몇 년은 일 안하고 먹고 살 수 있을 걸?","JPN":"リーグの賞金だけでも数年は働かなくても生きていける金額だぞ？","ENG":"With the league's prize money, we can live a comfortable life for a few years without having to work!","TWN":"光是聯賽獎金就足以讓我們不用工作好幾年吧？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"궁상맞게 이런 데서 상금 얘기 하지 마요! 아무렴 어때요!","JPN":"こんなときに賞金だの下世話なこと言わないでよ！　そんなのどうだっていいでしょ！","ENG":"Will you please stop talking about money right now?! Who cares?!","TWN":"別談獎金這種世俗的東西！獎金才不重要！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지금은…… 기뻐하기에도 바쁘니까!","JPN":"今は……喜ぶだけで精一杯なんだから！","ENG":"Because right now... I'm too busy being happy!","TWN":"重要的是……現在開心都來不及啦！"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"펠리세트도 저렇게 웃을 줄 아네. 처음 봤어.","JPN":"フェリセットもああやって笑えたんだね。初めて見たよ。","ENG":"I've never seen Félicette smile so happily before. Wow.","TWN":"費莉塞特也是會笑的，我還是第一次見。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"수고 많으셨어요, 사장님.","JPN":"お疲れ様でした、社長。","ENG":"Great supporting, Boss.","TWN":"辛苦了，老闆。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그리고 감사해요. 사장님 아니었으면 우승은커녕 예선 통과도 못 했을 테니까.","JPN":"そしてありがとうございます。社長がいらっしゃなかったら、優勝どころか予選通過すらできませんでした。","ENG":"And thank you. We would not have won, let alone passed the qualifiers, if it hadn't been for you.","TWN":"另外，謝謝老闆，要不是你，別說要奪冠，根本連通過預賽都不可能。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴 리가. 여기 온 건 순전히 자네들이 애쓴 덕분일세.","JPN":"まさか。ここまで上がってこれたのはあくまで君たちが頑張った結果だ。","ENG":"That's not true at all. You all made it this far on your own efforts.","TWN":"別這麼說，有今天的成果都是你們自己努力得來的。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이걸로 당장 무언가가 바뀌지는 않겠지.","JPN":"今すぐこれで何かが変わるというわけではないだろうが。","ENG":"Things won't change right away.","TWN":"雖說不會因此馬上就有什麼改變。"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 샤레이드의 시민들은 이번 리그에서 펼쳐졌던 사건도.","JPN":"しかしシャレードの市民たちは今回のリーグで起きた事件も。","ENG":"But the citizens of Charade won't forget what happened in this year's Gauntlet League,","TWN":"但相信查雷德的市民，不會忘記這次聯賽的種種……"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저 아이의 미소도 잊지 않을 거야.","JPN":"あの子の笑顔もきっと忘れないだろう。","ENG":"or the smile on Félicette's face.","TWN":"以及那個孩子的微笑。"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 이 정도 그림이면 만족하나?","JPN":"うむ、このぐらいの成果で十分か？","ENG":"But then again, isn't that enough for now?","TWN":"這樣的結果你還滿意嗎？"},"stage":{"bg":"CHARADE2_05","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"예. 스폰서들도 이번 일을 계기로 뒷공작에 어느 정도 미련을 버리겠죠.","JPN":"はい、スポンサーたちも今回の件をきっかけに、ある程度は裏工作への執着を捨てたでしょう。","ENG":"Yes. The sponsors will stop with their backdoor deals after today.","TWN":"是的，這次事件後，多少也會減少贊助商的黑幕吧。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"회의에서의 결정은 철회하도록 하겠습니다.","JPN":"会議で決定された事項は撤回することにします。","ENG":"I will withdraw the decision made during the last meeting.","TWN":"我會撤銷在會議上的決定。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"직접 인사를 드리게 되어 영광입니다. 최고 관리자님.","JPN":"この度、直接ご挨拶できて光栄です。最高管理者。","ENG":"It is an honor to finally greet you in person, Supreme Administrator.","TWN":"很榮幸能親自拜訪您，最高管理者。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"저 인원들로 단기간에 리그 우승까지 이끄시다니 놀랍군요.","JPN":"あのメンバーで短期間でのリーグ優勝を実現させるとは驚きました。","ENG":"I am amazed at how you could win the league in such a short amount of time with such limited personnel.","TWN":"能帶領那些成員在那麼短的時間內奪下聯賽冠軍，真是令人吃驚。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"클리포트 게임에서 활약한 워커 대령만큼은 아니더라도, S급 타이틀을 가진 카운터였는데 말입니다.","JPN":"クリフォトゲームで活躍したウォーカー大佐までとはいかずとも、相手はSランクのカウンターでしたのに。","ENG":"Even if she wasn't as strong as Colonel Walker, who participated in the Qliphoth Game, your opponent was still a Counter with a grade S title.","TWN":"雖說對方的程度在沃克上校之下，但起碼也是S級的制裁者。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"건틀렛이라 가능한 결과였지.","JPN":"ガントレットだからこそ可能だったんだ。","ENG":"It was only possible because it was the Gauntlet.","TWN":"因為是聖鎧，所以才有可能得出這種結果。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그게 건틀렛의 재미 아니겠나?","JPN":"そして、それこそがガントレットの面白さだろう？","ENG":"And that's what makes Gauntlet entertaining.","TWN":"而且，這就是聖鎧的樂趣不是嗎？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"후후, 그렇군요.","JPN":"ふふ、そうですね。","ENG":"Haha, indeed.","TWN":"呵呵，原來如此。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그런데 그 아티팩트는…… 예상하셨습니까?","JPN":"そういえば、あのアーティファクト……予想されていたんですか？","ENG":"But that Artifact... Did you know about it beforehand?","TWN":"不過，那個人造神器……也在您的預料之內嗎？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"강적이니 괜찮다고는 하지만, 혹시 모를 상황에 대비해 몇 가지 안전장치를 걸어 뒀지.","JPN":"強敵だから大丈夫だろうと思っていたが、万が一の状況に備えていくつか安全装置は用意していた。","ENG":"I assumed it would be okay to use it on such a formidable opponent, but I did place some safety measures just in case.","TWN":"雖然對手很強應該沒問題，但以防萬一，我還是有安排幾個安全裝置。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"축제에 피를 봐선 좋을 것 없지 않나?","JPN":"お祭りで流血事態は避けたいだろう？","ENG":"We cannot let bloodshed ruin a festival, no?","TWN":"畢竟在活動上見血不太好是嗎？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"……그렇죠. 동의합니다.","JPN":"……そうですね。確かに。","ENG":"...Absolutely not. I agree.","TWN":"……沒錯，我也同意。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 결승전에 <color=#ffd34c>형제들</color>이 잠입했더군. 확인하는 편이 좋을 걸세.","JPN":"あと、決勝戦に<color=#ffd34c>兄弟</color>が侵入していたぞ。確認した方がいいのではないか。","ENG":"I also heard that <color=#ffd34c>the brothers</color> infiltrated the finals. Perhaps you should check up on that.","TWN":"還有，我發現<color=#ffd34c>兄弟們</color>也有混入決賽，您最好確認一下。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"형제들이?","JPN":"兄弟が？","ENG":"The brothers?","TWN":"兄弟們？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 아마 플라티나의 사주일 겁니다.","JPN":"だとすると、おそらくプラチナの差し金でしょう。","ENG":"Oh, I presume that to be Platina's doing.","TWN":"應該是白金指使的。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 시기의 움직임이라면….","JPN":"しかし、この時期に動いたということは……","ENG":"But seeing how they mobilized in times like this...","TWN":"但挑在這個時候行動，說明……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자님. 실은 최근 신병을 확보한 육익의 일원에게 위험한 이야기를 들었습니다.","JPN":"最高管理者。実は最近身柄を確保した六翼から不穏な話を耳にしました。","ENG":"Supreme Administrator. I heard something ominous from a member of the Six Wings we captured recently.","TWN":"最高管理者，其實我們最近有抓到一個六翼的成員，她有向我們透露出一個危險的情報。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"예. 기밀인지라, 관리국에서 말씀드렸으면 합니다.","JPN":"はい。機密ですので、管理局でお話しいたします。","ENG":"As this is confidential information, I would like to report it to you at the Charade City Management.","TWN":"不過因為是機密，我希望能在管理局裡談。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"명목상으로는 리그 우승 상품 전달과…… 보관 중인 압류품의 반환이 좋을 듯합니다.","JPN":"表向きとしては、リーグ優勝賞品の受け渡しと……保管中の差押え品の返還とする方がいいでしょう。","ENG":"We would be meeting for the delivery of the league's prize for the winner... and the return of the seized items.","TWN":"名義可以用頒發聯賽優勝獎品……和歸回保管中的扣押物。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"알겠네. 준비해 두게나.","JPN":"わかった、準備してくれたまえ。","ENG":"Very well. Have it prepared.","TWN":"好，我再準備一下。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"감사합니다. 저는 시상식 때문에 먼저 가 봐야겠군요.","JPN":"ありがとうございます。私は表彰式があるのでお先に失礼します。","ENG":"Thank you. Then, if you will excuse me, I must get going for the award ceremony.","TWN":"謝謝，等一下還有頒獎典禮，我要先走一步。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 연락 주시길 기다리겠습니다.","JPN":"では、ご連絡お待ちしております。","ENG":"Then, I shall be waiting for your call.","TWN":"那就等候您的通知。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};